import os, re, json, pickle
from collections import defaultdict

OD='raw_orders'; SD='raw_supplier_receipts'; WD='raw_wholesaler_receipts'; SR='raw_wholesaler_store_receipts'

def parse_items(path, fmt, qty_keys):
    """Return dict product->qty for order/supplier files."""
    items={}
    with open(path) as f: txt=f.read()
    if fmt=='api-json.json':
        d=json.loads(txt)
        for it in d['items']:
            pid=it.get('prod_id') or it.get('product')
            q=None
            for k in qty_keys:
                if k in it: q=it[k]; break
            items[pid]=int(q)
    elif fmt=='table-csv.csv':
        lines=[l for l in txt.strip().splitlines() if l.strip()]
        for l in lines[1:]:
            a,b=l.split(';'); items[a.strip()]=int(b)
    elif fmt=='key-value.txt':
        for l in txt.strip().splitlines():
            # order: RECEIVER: S_x | ORDER_PRODUCT: P | ORDER_QTY: n
            # supplier: SUPPLIER: PR | DAY: d  (header) ; PRODUCT: P | DELIVERED_QTY: n
            m=re.search(r'(?:ORDER_PRODUCT|PRODUCT):\s*(P_\d+).*?(?:ORDER_QTY|DELIVERED_QTY):\s*(\d+)', l)
            if m: items[m.group(1)]=int(m.group(2))
    elif fmt=='text-template.txt':
        for l in txt.strip().splitlines():
            m=re.search(r'(\d+)\s+units of product\s+(P_\d+)', l)
            if m: items[m.group(2)]=int(m.group(1))
    return items

orders=defaultdict(dict)     # (day,store)->{prod:qty}
supplier=defaultdict(dict)   # (day,prod_producer)-> {prod:qty}
for fn in os.listdir(OD):
    m=re.match(r'day_(\d+)_(S_\d+)_(.*)',fn)
    day=int(m.group(1)); store=m.group(2); fmt=m.group(3)
    orders[(day,store)]=parse_items(os.path.join(OD,fn),fmt,['qty'])
for fn in os.listdir(SD):
    m=re.match(r'day_(\d+)_(PR_\d+)_(.*)',fn)
    day=int(m.group(1)); pr=m.group(2); fmt=m.group(3)
    supplier[(day,pr)]=parse_items(os.path.join(SD,fn),fmt,['delivered_qty'])

# wholesaler producer sequence
wseq=defaultdict(dict)  # day-> {producer: seq}
for fn in os.listdir(WD):
    with open(os.path.join(WD,fn)) as f: t=f.read()
    day=int(re.search(r'DAY:\s*(\d+)',t).group(1))
    pr=re.search(r'SUPPLIER_ID:\s*(PR_\d+)',t).group(1)
    seq=int(re.search(r'DAILY_SEQUENCE_NO:\s*(\d+)',t).group(1))
    wseq[day][pr]=seq
# store sequence + total
sseq=defaultdict(dict)  # day-> {store: (seq,total)}
for fn in os.listdir(SR):
    with open(os.path.join(SR,fn)) as f: t=f.read()
    day=int(re.search(r'DAY:\s*(\d+)',t).group(1))
    st=re.search(r'STORE_ID:\s*(S_\d+)',t).group(1)
    seq=int(re.search(r'DAILY_SEQUENCE_NO:\s*(\d+)',t).group(1))
    tot=int(re.search(r'TOTAL_DELIVERED_UNITS:\s*(\d+)',t).group(1))
    sseq[day][st]=(seq,tot)

pickle.dump({'orders':dict(orders),'supplier':dict(supplier),'wseq':dict(wseq),'sseq':dict(sseq)},
            open('/tmp/raw.pkl','wb'))
print("parsed. orders:",len(orders),"supplier:",len(supplier),"wseq days:",len(wseq),"sseq days:",len(sseq))
# sanity checks
print("sample order (1,S_1) P_1:",orders[(1,'S_1')].get('P_1'))
print("sample supplier (1,PR_10):",supplier[(1,'PR_10')])
print("wseq day1 PR_10 seq:",wseq[1]['PR_10'], " producers day1:",len(wseq[1]))
print("sseq day1 S_1:",sseq[1]['S_1']," stores day1:",len(sseq[1]))
