orders,supplier,wseq,sseq=R['orders'],R['supplier'],R['wseq'],R['sseq']
PRODS=[f'P_{i}' for i in range(1,31)]

def alloc_day(day, carry=None):
    stock={p:[] for p in PRODS}
    if carry:
        for p in PRODS: stock[p]=[list(x) for x in carry[p]]
    for pr in sorted(wseq[day],key=lambda x:wseq[day][x]):
        for p,q in supplier[(day,pr)].items():
            stock[p].append([pr,q])
    deliv={}
    for st in sorted(sseq[day],key=lambda x:sseq[day][x][0]):
        od=orders.get((day,st),{}); d={}
        for p in PRODS:
            need=od.get(p,0); got=0
            while need>0 and stock[p]:
                pr,q=stock[p][0]; take=min(need,q); got+=take; need-=take; q-=take
                if q==0: stock[p].pop(0)
                else: stock[p][0][1]=q
            if got>0: d[p]=got
        deliv[st]=d
    leftover=sum(sum(x[1] for x in stock[p]) for p in PRODS)
    return deliv, stock, leftover

