# deliveries with producer composition: deliv[day][store][prod]=list of [producer,qty] in queue order
def alloc_all():
    deliv={d:{s:{} for s in STORES} for d in range(1,366)}
    for day in range(1,366):
        stock={p:[] for p in PRODS}
        for pr in sorted(wseq[day],key=lambda x:wseq[day][x]):
            for p,q in supplier[(day,pr)].items():
                stock[p].append([pr,q])
        for st in sorted(sseq[day],key=lambda x:sseq[day][x][0]):
            od=orders.get((day,st),{})
            for p in PRODS:
                need=od.get(p,0); comp=[]
                while need>0 and stock[p]:
                    pr,q=stock[p][0]; take=min(need,q); need-=take; q-=take
                    comp.append([pr,take])
                    if q==0: stock[p].pop(0)
                    else: stock[p][0][1]=q
